import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-download.IKA_571t.js";const a=JSON.parse(`{"title":"Настройка IntelliJ IDEA","description":"Пошаговое руководство по настройке IntelliJ IDEA для создания модов с помощью Fabric.","frontmatter":{"title":"Настройка IntelliJ IDEA","description":"Пошаговое руководство по настройке IntelliJ IDEA для создания модов с помощью Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","dicedpixels","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"prev":{"text":"Настройка IDE","link":"../setting-up"},"next":{"text":"Открытие проекта в IntelliJ IDEA","link":"./opening-a-project"},"files":[]},"headers":[],"relativePath":"ru_ru/develop/getting-started/intellij-idea/setting-up.md","filePath":"translated/ru_ru/develop/getting-started/intellij-idea/setting-up.md","lastUpdated":1770561656000}`);var o={name:`ru_ru/develop/getting-started/intellij-idea/setting-up.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Настройка IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Настройка IntelliJ IDEA”">​</a></h1><div class="info custom-block"><p class="custom-block-title">ТРЕБОВАНИЯ</p><p>Сначала убедитесь, что вы <a href="./../setting-up#install-jdk-21">установили JDK</a>.</p></div><h2 id="installing-intellij-idea" tabindex="-1">Установка IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Установка IntelliJ IDEA”">​</a></h2><p>Если у вас не установлена IntelliJ IDEA, вы можете загрузить ее с <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">официального сайта</a> - выполните шаги по установке для вашей ОС.</p><p><img src="/assets/develop/getting-started/idea-download.png" alt="Страница загрузки IntelliJ IDEA" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Установка плагина &quot;Minecraft Development&quot; <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Установка плагина &quot;Minecraft Development&quot;”">​</a></h2><p>Плагин Minecraft Development обеспечивает поддержку моддинга с помощью Fabric, и это самый важный плагин, который необходимо установить.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Хотя этот плагин не является строго необходимым, он может значительно облегчить работу над модом Fabric - вам стоит подумать о его установке.</p></div><p>Вы можете установить его, открыв IntelliJ IDEA, а затем перейдя на вкладку <strong>Файл</strong> &gt; <strong>Настройки</strong> &gt; <strong>Плагины</strong> &gt; <strong>Marketplace</strong>, затем найдите <code>Minecraft Development</code> в строке поиска и нажмите кнопку <strong>Установить</strong>.</p><p>Также вы можете загрузить его со страницы <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">страница плагина</a>, а затем установить, перейдя по пути <strong>Файл</strong> &gt; <strong>Настройки</strong> &gt; <strong>Плагины</strong> &gt; <strong>Установка плагина с диска</strong>.</p><h3 id="about-creating-a-project" tabindex="-1">О создании проекта <a class="header-anchor" href="#about-creating-a-project" aria-label="Permalink to “О создании проекта”">​</a></h3><p>Хотя можно создать проект с помощью этого плагина, делать это не рекомендуется, поскольку шаблоны часто устаревают. Вместо этого воспользуйтесь <a href="./.../creating-a-project">Создание проекта</a>, чтобы использовать Fabric Template Mod Generator.</p>`,12)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};